// Removes legacy static .html files from dist/ that collide with SPA routes.
// Cloudflare Pages serves static .html before falling back to index.html,
// so we must delete these or every SPA route gets intercepted.
//
// Keep ONLY index.html (SPA entry). Everything else generated by Vite's
// multi-page input is legacy and conflicts with React Router.
import fs from "fs";
import path from "path";

const dist = path.resolve("dist");
if (!fs.existsSync(dist)) {
  console.log("strip-spa-conflicts: dist/ does not exist, skipping");
  process.exit(0);
}

const keep = new Set(["index.html"]);
let removed = 0;
for (const entry of fs.readdirSync(dist)) {
  if (entry.endsWith(".html") && !keep.has(entry)) {
    fs.unlinkSync(path.join(dist, entry));
    removed++;
  }
}

// Also strip subdir HTML files except sandbox-only utility pages
const subdirs = ["admin", "src", "test"];
for (const sub of subdirs) {
  const subPath = path.join(dist, sub);
  if (!fs.existsSync(subPath)) continue;
  walk(subPath);
}

function walk(dir) {
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) walk(full);
    else if (entry.isFile() && entry.name.endsWith(".html")) {
      fs.unlinkSync(full);
      removed++;
    }
  }
}

console.log(`strip-spa-conflicts: removed ${removed} legacy .html files`);
